SELECT P.prod_no AS product_id, P.prod_nm AS product_name, P.prod_type AS product_type, P.apv_stat_cd AS approve_status, P.reg_dt AS create_date, P.reg_by AS created_by, P.tgt_lrg AS target_large, P.tgt_dtl AS target_detail, P.rate_cat AS rate_category, P.min_prd_mon AS min_period_month, P.max_prd_mon AS max_period_month, P.min_amt AS min_amount, P.max_amt AS max_amount, P.prod_desc AS product_desc, P.int_pay_type AS interest_payment_type, P.apld_exch_type AS applied_exchange_rate_type, C.prod_cur_no, C.cur_cd, C.cur_nm, C.is_avail AS avail FROM PRODUCTS P LEFT JOIN PRODUCT_CURRENCIES C ON P.prod_no = C.prod_no AND C.is_avail = 'Y' WHERE 1=1
AND P.prod_nm LIKE '%' || #{keyword} || '%'
AND P.prod_type = #{type}
AND P.apv_stat_cd = #{status}
ORDER BY P.prod_no DESC OFFSET #{offset} ROWS FETCH NEXT #{pageSize} ROWS ONLY

SELECT COUNT(*)
FROM products
WHERE 1=1


